#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int minMeetingRooms(int** intervals, int intervalsSize, int* intervalsColSize) {
    if (intervalsSize == 0) return 0;
    int* starts = (int*)malloc(intervalsSize * sizeof(int));
    int* ends = (int*)malloc(intervalsSize * sizeof(int));
    for (int i = 0; i < intervalsSize; i++) {
        starts[i] = intervals[i][0];
        ends[i] = intervals[i][1];
    }
    qsort(starts, intervalsSize, sizeof(int), compare);
    qsort(ends, intervalsSize, sizeof(int), compare);
    int i = 0, j = 0, rooms = 0, maxRooms = 0;
    while (i < intervalsSize && j < intervalsSize) {
        if (starts[i] < ends[j]) {
            rooms++;
            i++;
        } else {
            rooms--;
            j++;
        }
        maxRooms = (maxRooms > rooms) ? maxRooms : rooms;
    }
    free(starts);
    free(ends);
    return maxRooms;
}

